const formData = $('On form submission').first().json;
const cv = $input.first().json.cv || [];

return [{
  json: {
    notes: formData['Notes'] || '',
    cv: cv
  },
  binary: {
    job_posting: $('On form submission').first().binary['Job_posting']
  }
}];

const job = $input.first().json.data;
const cv = $('Prep Data').first().json.cv || [];
const notes = $('Prep Data').first().json.notes || '';

function toArray(value) {
  // Already an array — return as-is.
  if (Array.isArray(value)) return value;

  // String — try JSON first, then comma-split as fallback.
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return [];

    // Try JSON parse first (covers "[\"a\", \"b\"]" responses).
    try {
      const parsed = JSON.parse(trimmed);
      if (Array.isArray(parsed)) return parsed;
    } catch (e) { /* fall through to comma split */ }

    // Fallback: comma-separated string.
    return trimmed.split(',').map(s => s.trim()).filter(Boolean);
  }

  return [];
}

const mustHaves = toArray(job.must_have_skills);
const keywords = toArray(job.keywords);

const cvText = cv.map(row =>
  `${row.role || ''} ${row.company || ''} ${row.bullets || ''} ${row.skills || ''}`
).join(' ').toLowerCase();

function normalize(s) { return String(s || '').toLowerCase().trim(); }

function matches(haystack, needle) {
  const n = normalize(needle);
  if (!n) return false;
  if (haystack.includes(n)) return true;
  if (n.endsWith('s') && haystack.includes(n.slice(0, -1))) return true;
  return false;
}

const matchedMust = mustHaves.filter(s => matches(cvText, s));
const matchedKw = keywords.filter(s => matches(cvText, s));
const missingMust = mustHaves.filter(s => !matches(cvText, s));
const missingKw = keywords.filter(s => !matches(cvText, s));

const totalWeight = (mustHaves.length * 2) + keywords.length;
const earned = (matchedMust.length * 2) + matchedKw.length;
const scoreBefore = totalWeight === 0 ? 0 : Math.round((earned / totalWeight) * 100);

return [{
  json: {
    job,
    cv,
    notes,
    score_before: scoreBefore,
    matched_must_have: matchedMust,
    missing_must_have: missingMust,
    matched_keywords: matchedKw,
    missing_keywords: missingKw
  }
}];

