// Extract Gemini's text output. The shape varies depending on the Gemini node version.
const input = $input.first().json;

let rawText = '';
if (input?.content?.parts?.[0]?.text) {
  // Gemini API native shape (your current case).
  rawText = input.content.parts[0].text;
} else if (typeof input.text === 'string') {
  rawText = input.text;
} else if (typeof input.response === 'string') {
  rawText = input.response;
} else if (typeof input.output === 'string') {
  rawText = input.output;
} else if (input?.message?.content) {
  rawText = input.message.content;
} else {
  rawText = JSON.stringify(input);
}

// Strip markdown fences if present.
const cleaned = String(rawText).replace(/```json|```/g, '').trim();

let tailored;
try {
  tailored = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Could not parse Gemini output as JSON. First 500 chars: ' + cleaned.slice(0, 500));
}

// Pull previous state from the Score: Before node.
const prev = $('Score: Before').first().json;
const job = prev.job;
const cv = prev.cv;
const notes = prev.notes;

// Same toArray helper as Phase 3 — handles arrays, JSON strings, comma-separated strings.
function toArray(value) {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return [];
    try {
      const parsed = JSON.parse(trimmed);
      if (Array.isArray(parsed)) return parsed;
    } catch (e) { /* fall through */ }
    return trimmed.split(',').map(s => s.trim()).filter(Boolean);
  }
  return [];
}

const mustHaves = toArray(job.must_have_skills);
const keywords = toArray(job.keywords);

// Build the new searchable text from the TAILORED bullets.
const tailoredText = (tailored.experiences || []).map(exp =>
  `${exp.role || ''} ${exp.company || ''} ${(exp.bullets || []).join(' ')}`
).join(' ').toLowerCase();

function normalize(s) { return String(s || '').toLowerCase().trim(); }

function matches(haystack, needle) {
  const n = normalize(needle);
  if (!n) return false;
  if (haystack.includes(n)) return true;
  if (n.endsWith('s') && haystack.includes(n.slice(0, -1))) return true;
  return false;
}

const matchedMust = mustHaves.filter(s => matches(tailoredText, s));
const matchedKw = keywords.filter(s => matches(tailoredText, s));
const missingMust = mustHaves.filter(s => !matches(tailoredText, s));
const missingKw = keywords.filter(s => !matches(tailoredText, s));

const totalWeight = (mustHaves.length * 2) + keywords.length;
const earned = (matchedMust.length * 2) + matchedKw.length;
const scoreAfter = totalWeight === 0 ? 0 : Math.round((earned / totalWeight) * 100);

return [{
  json: {
    job,
    cv,
    notes,
    tailored_experiences: tailored.experiences || [],
    gaps: tailored.gaps || [],
    score_before: prev.score_before,
    score_after: scoreAfter,
    score_delta: scoreAfter - prev.score_before,
    matched_must_have_after: matchedMust,
    missing_must_have_after: missingMust,
    matched_keywords_after: matchedKw,
    missing_keywords_after: missingKw
  }
}];

