// Get the cover letter from this node's input (Gemini #2 output).
const coverInput = $input.first().json;
const letter = coverInput?.content?.parts?.[0]?.text 
  || coverInput?.text 
  || coverInput?.response 
  || '';

// Get everything else from Score: After.
const data = $('Score: After').first().json;

// Build the experience block — one section per role.
const expBlocks = (data.tailored_experiences || []).map(exp => {
  const bullets = (exp.bullets || []).map(b => `• ${b}`).join('\n');
  return `${exp.role} — ${exp.company}\n${exp.dates}\n${bullets}`;
}).join('\n\n');

// Optional gaps section — only included if there are any.
const gapsBlock = data.gaps && data.gaps.length
  ? `\n\n---\nGAPS TO ADDRESS IN INTERVIEW:\n${data.gaps.map(g => `• ${g}`).join('\n')}`
  : '';

// Full document body — single string, line breaks preserved.
const body = `TAILORED CV — ${data.job.job_title || 'Application'}
Match: ${data.score_before}% → ${data.score_after}% (+${data.score_delta})

${expBlocks}${gapsBlock}

=========================

COVER LETTER

${letter}`;

return [{
  json: {
    doc_title: `Application - ${data.job.company || 'Company'} - ${data.job.job_title || 'Role'}`,
    doc_body: body,
    score_before: data.score_before,
    score_after: data.score_after,
    score_delta: data.score_delta,
    gaps: data.gaps || [],
    company: data.job.company,
    job_title: data.job.job_title
  }
}];
